# After spec is parsed, before job insertion loop:
try:
    compiler = StepCompiler()
    # Build scope dict from spec jobs
    scope = {
        'write_scope': [],
        'read_scope': {},
    }
    for job in spec.jobs:
        if hasattr(job, 'write_scope') and job.write_scope:
            for path in job.write_scope:
                scope['write_scope'].append({'path': path, 'action': 'modify'})
        if hasattr(job, 'read_scope') and job.read_scope:
            scope['read_scope'][job.label] = job.read_scope

    if scope['write_scope']:
        plan = compiler.compile(scope)
        # Extract auto-detected dependencies
        auto_deps = {}
        for step in plan.steps:
            if step.depends_on:
                auto_deps[step.step_id] = list(step.depends_on)
        # Merge auto-deps with explicit depends_on (explicit wins)
        for job in spec.jobs:
            if job.label in auto_deps and not getattr(job, 'depends_on', None):
                job.depends_on = auto_deps[job.label]
except Exception:
    pass  # Graceful degradation: if strategy analysis fails, fall through to explicit deps
